function StructPetDreamLandData:StructPetDreamLandData()
	---@type number 幻境refId
	self.refId = 0

	---@type number 已被占据据点数量
	self.pointNum = 0

	---@type table<string,StructPetDreamLandPointData> 据点数据 Map 包含玩家数据
	self.pointDataMap = {}

