end

function StructPetDreamLandData:CreateByPb(pb)
	self:SetRefId(pb.refId)

	self.pointNum = pb.pointNum

	self.pointDataMap = {}
	local pointData = pb.pointData or {}
	for i,v in ipairs(pointData) do
		---@type StructPetDreamLandPointData
		local data = StructPetDreamLandPointData:New()
		data:CreateByPb(v)
		self.pointDataMap[data.id] = data
	end

	self.playerPointDataMap = {}
	local playerPointData = pb.playerPointData or {}
	for i,v in ipairs(playerPointData) do
		---@type StructPetDreamLandPointData
		local data = StructPetDreamLandPointData:New()
		data:CreateByPb(v)
		self.playerPointDataMap[data.id] = data
	end

	self.occupyNum = 0
	self:UpdateOccupyState()
end

function StructPetDreamLandData:SetRefId(refId)
	self.refId = refId
end

function StructPetDreamLandData:UpdateOccupyState()
	local state = 0
	for k,v in pairs(self.playerPointDataMap) do
		state = state + 1
	end
	self.occupyNum = state
end

---@return number 返回玩家占领的数量
function StructPetDreamLandData:GetPlayerOccupyNum()
	return self.occupyNum
end

function StructPetDreamLandData:CheckIsPlayerOccupy()
	return self.occupyNum > 0
end

