function StructPetDreamLandData:GetPointNum()
	return self.pointNum
end

---@return table<StructPetDreamLandPointData>
function StructPetDreamLandData:GetPlayerPointDatas()
	local list = {}
	for k,v in pairs(self.playerPointDataMap) do
		table.insert(list,v)
	end
