end

---@type boolean 是否在收集中
function StructPetDreamLandData:CheckHasCollect()
	local list = self:GetPlayerPointDatas()
	return #list > 0
end

---@type number 获取玩家节点的时间
function StructPetDreamLandData:GetPlayerPointDataTime()
	if not self:CheckHasCollect() then return -1 end
	local list = self:GetPlayerPointDatas()
	---@type StructPetDreamLandPointData
	local playerPointData = list[1]
	return playerPointData.starOccupyTime
end

---@param data StructPetDreamLandPointData
function StructPetDreamLandData:UpdatePetDreamLandPointData(data)
	self.pointDataMap[data.id] = data
	self.playerPointDataMap[data.id] = data
	self:UpdateOccupyState()
	self:UpdatePointNum()
end

---@param data StructPetDreamLandPointData
function StructPetDreamLandData:UpdatePetDreamLandPointData1(data)
	for k,v in pairs(self.pointDataMap) do
		if v.id == data.id then
			self.pointDataMap[data.id] = data
		end
	end
	local myPlayerId = gModelPlayer:GetPlayerId()
	if myPlayerId == data.playerId then
		self.playerPointDataMap[data.id] = data
	end
	self:UpdateOccupyState()
	self:UpdatePointNum()
end

function StructPetDreamLandData:DelectPetDreamLandPointData(pointId)
	self.pointDataMap[pointId] = nil
	self.playerPointDataMap[pointId] = nil
	self:UpdateOccupyState()
	self:UpdatePointNum()
end

function StructPetDreamLandData:UpdatePointNum()
	local num = 0
	for k,v in pairs(self.pointDataMap) do
		num = num + 1
	end
	self.pointNum = num
end

--- 获取所有据点列表
---@return table<StructPetDreamLandPointData>
function StructPetDreamLandData:GetPointDatas()
	---@type table<StructPetDreamLandPointData>
	local list = {}
	for k,v in pairs(self.pointDataMap) do
		table.insert(list,v)
	end

	---@param a StructPetDreamLandPointData
	---@param b StructPetDreamLandPointData
	table.sort(list,function(a, b)
		local isMyA = a:CheckIsMyPoint() and 1 or 0
		local isMyB = b:CheckIsMyPoint() and 1 or 0
		if isMyA ~= isMyB then
			return isMyA > isMyB
		end

		local notInitProA = a:CheckIsNoInitProtect() and 1 or 0
		local notInitProB = b:CheckIsNoInitProtect() and 1 or 0
		if notInitProA ~= notInitProB then
			return notInitProA > notInitProB
		end

		local powerA = a:GetPlayerPower()
		local powerB = b:GetPlayerPower()
		if powerA ~= powerB then
			return powerA < powerB
		end

		local notAttackedProA = a:CheckIsNoAttackedProtect() and 1 or 0
		local notAttackedProB = b:CheckIsNoAttackedProtect() and 1 or 0
		if notAttackedProA ~= notAttackedProB then
			return notAttackedProA > notAttackedProB
		end

		return tonumber(a.id) < tonumber(b.id)
	end)
	return list
end

return StructPetDreamLandData